-- =====================================================================
-- 吉林小串：清空门店/商品相关演示数据并导入菜单（MySQL）
-- 执行前请备份数据库。按需修改以下会话变量：
-- 本库无 yshop_store_cart（与 yixiang-drink-open.sql 建表一致），不再执行购物车表 DELETE。
-- =====================================================================
SET NAMES utf8mb4;
SET @tenant_id := 1;
-- 门店管理员用户 id（system_users.id），默认 1；请改为实际账号
SET @admin_user_id := '1';
-- 占位图（商品主图/轮播，NOT NULL；可改为你的 CDN 地址）
SET @placeholder_img := '';

START TRANSACTION;

-- ----- 可选：清空订单（演示环境推荐） -----
DELETE FROM yshop_store_order_status WHERE 1=1;
DELETE FROM yshop_store_order_cart_info WHERE 1=1;
DELETE FROM yshop_store_order WHERE 1=1;
DELETE FROM yshop_order_number WHERE 1=1;

-- ----- 商品从表 -----
DELETE FROM yshop_store_product_attr_value WHERE 1=1;
DELETE FROM yshop_store_product_attr WHERE 1=1;
DELETE FROM yshop_store_product_attr_result WHERE 1=1;
DELETE FROM yshop_store_product_relation WHERE 1=1;
-- 本库若存在 yshop_store_product_reply 可手工清空；外网部分仅按 yixiang-drink-open 子集初始化时无此表，
-- 执行 DELETE 会 1146，故不在此脚本中删除该表。

-- ----- 商品与分类 -----
DELETE FROM yshop_store_product WHERE 1=1;
DELETE FROM yshop_store_product_category WHERE 1=1;

-- ----- 广告（含吉林小串店铺） -----
DELETE FROM yshop_shop_ads WHERE 1=1;

-- ----- 仅保留即将插入的门店：删除全部旧门店 -----
DELETE FROM yshop_store_shop WHERE 1=1;

-- ----- 插入唯一门店「吉林小串」 -----

SET @shop_id := 1;
-- 与插入的门店 id 对齐 AUTO_INCREMENT（避免后续手动插入 id 冲突）
ALTER TABLE yshop_store_shop AUTO_INCREMENT = 2;

-- ----- 9 个一级分类 -----

-- ----- 商品：肉类/成把/鱼/肠/素菜 为双规格（规格+辣度，spec_type=1）；其余单规格（spec_type=0） -----

ALTER TABLE yshop_store_product AUTO_INCREMENT = 30072;
ALTER TABLE yshop_store_product_category AUTO_INCREMENT = 9010;
ALTER TABLE yshop_store_product_attr AUTO_INCREMENT = 800128;
ALTER TABLE yshop_store_product_attr_result AUTO_INCREMENT = 810071;
ALTER TABLE yshop_store_product_attr_value AUTO_INCREMENT = 820242;

COMMIT;

-- 校验：分类 9 条、商品 71 条
